CREATE TABLE associate_model_quants
(
	id serial,
	risk_model_id integer NOT NULL,
	associate_model_id integer NOT NULL,
	quant_id integer NOT NULL,
	created_by_id integer DEFAULT NULL,
	updated_by_id integer DEFAULT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_associate_model_quants PRIMARY KEY (id)
	, CONSTRAINT fk_associate_model_quants_to_risk_model FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_model_quants_to_associate_model FOREIGN KEY (associate_model_id) REFERENCES associate_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_model_quants_to_quant FOREIGN KEY (quant_id) REFERENCES quant_metrics (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_model_quants_to_created_by FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_model_quants_to_updated_by FOREIGN KEY (updated_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_associate_model_quants_risk_model ON associate_model_quants (risk_model_id);
CREATE INDEX i_associate_model_quants_associate_model ON associate_model_quants (associate_model_id);
CREATE INDEX i_associate_model_quants_quant ON associate_model_quants (quant_id);
CREATE INDEX i_associate_model_quants_created_at ON associate_model_quants (created_at);
CREATE INDEX i_associate_model_quants_created_by ON associate_model_quants (created_by_id);
CREATE INDEX i_associate_model_quants_updated_by ON associate_model_quants (updated_by_id);
